(function(){const TOKEN="__BOT_IBON__";window.addEventListener("message",function(n){if(n.data&&n.data.type===TOKEN){var script=n.data.script;console.log("[inject] 收到指令:",script);var m=script.match(/Send\s*\(\s*([\s\S]*?)\s*\)\s*;?\s*$/i);if(m&&"function"==typeof window.Send)try{var args=new Function("return ["+m[1]+"]")();return console.log("[inject] 執行 Send, args:",args),void window.Send.apply(window,args)}catch(n){console.log("[inject] Send 失敗:",n.message)}try{return void eval(script)}catch(n){console.log("[inject] eval 失敗:",n.message)}console.log("[inject] 所有方法失敗")}}),console.log("[inject] ✅ 已就緒 TOKEN="+TOKEN)})();